from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager, jwt_required, create_access_token, get_raw_jwt
import datetime
from hashlib import sha256
import os

app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = 'super-secret'  # Replace with your own secret key
jwt = JWTManager(app)

users = {
    "user1": "password1",
    "user2": "password2"
}

@app.route('/register', methods=['POST'])
def register():
    if request.json and 'username' in request.json and 'password' in request.json:
        username = request.json['username']
        password = request.json['password']
        if username not in users:
            users[username] = password
            return jsonify({"message": "User created successfully!"}), 201
        else:
            return jsonify({"message": "Username already exists."}), 409
    else:
        return jsonify({"message": "Invalid request data."}), 400

@app.route('/login', methods=['POST'])
def login():
    if request.json and 'username' in request.json and 'password' in request.json:
        username = request.json['username']
        password = request.json['password']
        if username in users and users[username] == password:
            access_token = create_access_token(identity=username)
            return jsonify(access_token=access_token), 200
        else:
            return jsonify({"message": "Invalid credentials."}), 401
    else:
        return jsonify({"message": "Invalid request data."}), 400

@app.route('/protected', methods=['GET'])
@jwt_required()
def protected():
    try:
        current_user = get_raw_jwt()['sub']
        return jsonify({"message": f"Hello {current_user}!", "token": get_raw_jwt()}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 401

if __name__ == '__main__':
    app.run(debug=True)